    4861:     static char_u *
    4862: concat_pattern_with_buffer_match(
    4863: 	char_u *pat,
    4864: 	int pat_len,
    4865: 	pos_T *end_match_pos,
    4866: 	int lowercase UNUSED)
    4867: {
    4868:     char_u  *line = ml_get(end_match_pos->lnum);
    4869:     char_u  *word_end = find_word_end(line + end_match_pos->col);
    4870:     int	    match_len = (int)(word_end - (line + end_match_pos->col));
>>  4871:     char_u  *match = alloc(match_len + pat_len + 1);  // +1 for NUL
    4872: 
    4873:     if (match == NULL)
    4874: 	return NULL;
    4875:     mch_memmove(match, pat, pat_len);
    4876:     if (match_len > 0)
    4877:     {
    4878: #if defined(FEAT_EVAL) || defined(FEAT_SPELL)
    4879: 	if (lowercase)
    4880: 	{
    4881: 	    char_u  *mword = vim_strnsave(line + end_match_pos->col,
    4882: 		    match_len);
    4883: 	    if (mword == NULL)
    4884: 		goto cleanup;
    4885: 	    char_u  *lower = strlow_save(mword);
    4886: 	    vim_free(mword);
    4887: 	    if (lower == NULL)
    4888: 		goto cleanup;
    4889: 	    mch_memmove(match + pat_len, lower, match_len);
    4890: 	    vim_free(lower);
    4891: 	}
    4892: 	else
    4893: #endif
    4894: 	    mch_memmove(match + pat_len, line + end_match_pos->col, match_len);
    4895:     }
    4896:     match[pat_len + match_len] = NUL;
    4897:     return match;
    4898: 
    4899: #if defined(FEAT_EVAL) || defined(FEAT_SPELL)
    4900: cleanup:
    4901:     vim_free(match);
    4902:     return NULL;
    4903: #endif
    4904: }

