     796:     static int
     797: diff_write_buffer(buf_T *buf, diffin_T *din, linenr_T start, linenr_T end)
     798: {
     799:     linenr_T	lnum;
     800:     char_u	*s;
     801:     long	len = 0;
     802:     char_u	*ptr;
     803: 
     804:     if (end < 0)
     805: 	end = buf->b_ml.ml_line_count;
     806: 
     807:     if (buf->b_ml.ml_flags & ML_EMPTY || end < start)
     808:     {
     809: 	din->din_mmfile.ptr = NULL;
     810: 	din->din_mmfile.size = 0;
     811: 	return OK;
     812:     }
     813: 
     814:     // xdiff requires one big block of memory with all the text.
     815:     for (lnum = start; lnum <= end; ++lnum)
     816: 	len += ml_get_buf_len(buf, lnum) + 1;
>>   817:     ptr = alloc(len);
     818:     if (ptr == NULL)
     819:     {
     820: 	// Allocating memory failed.  This can happen, because we try to read
     821: 	// the whole buffer text into memory.  Set the failed flag, the diff
     822: 	// will be retried with external diff.  The flag is never reset.
     823: 	buf->b_diff_failed = TRUE;
     824: 	if (p_verbose > 0)
     825: 	{
     826: 	    verbose_enter();
     827: 	    smsg(_("Not enough memory to use internal diff for buffer \"%s\""),
     828: 								 buf->b_fname);
     829: 	    verbose_leave();
     830: 	}
     831: 	return FAIL;
     832:     }
     833:     din->din_mmfile.ptr = (char *)ptr;
     834:     din->din_mmfile.size = len;
     835: 
     836:     len = 0;
     837:     for (lnum = start; lnum <= end; ++lnum)
     838:     {
     839: 	for (s = ml_get_buf(buf, lnum, FALSE); *s != NUL; )
     840: 	{
     841: 	    if (diff_flags & DIFF_ICASE)
     842: 	    {
     843: 		int c;
     844: 		int	orig_len;
     845: 		int	c_len = 1;
     846: 		char_u	cbuf[MB_MAXBYTES + 1];
     847: 
     848: 		if (*s == NL)
     849: 		    c = NUL;
     850: 		else
     851: 		{
     852: 		    // xdiff doesn't support ignoring case, fold-case the text.
     853: 		    c = PTR2CHAR(s);
     854: 		    c_len = MB_CHAR2LEN(c);
     855: 		    c = MB_CASEFOLD(c);
     856: 		}
     857: 		orig_len = mb_ptr2len(s);
     858: 		if (mb_char2bytes(c, cbuf) != c_len)
     859: 		    // TODO: handle byte length difference.
     860: 		    // One example is Å (3 bytes) and å (2 bytes).
     861: 		    mch_memmove(ptr + len, s, orig_len);
     862: 		else
     863: 		{
     864: 		    mch_memmove(ptr + len, cbuf, c_len);
     865: 		    if (orig_len > c_len)
     866: 		    {
     867: 			// Copy remaining composing characters
     868: 			mch_memmove(ptr + len + c_len, s + c_len,
     869: 				orig_len - c_len);
     870: 		    }
     871: 		}
     872: 
     873: 		s += orig_len;
     874: 		len += orig_len;
     875: 	    }
     876: 	    else
     877: 	    {
     878: 		ptr[len++] = *s == NL ? NUL : *s;
     879: 		s++;
     880: 	    }
     881: 	}
     882: 	ptr[len++] = NL;
     883:     }
     884:     return OK;
     885: }

