     854: 		    c_len = MB_CHAR2LEN(c);
     855: 		    c = MB_CASEFOLD(c);
     856: 		}
     857: 		orig_len = mb_ptr2len(s);
     858: 		if (mb_char2bytes(c, cbuf) != c_len)
     859: 		    // TODO: handle byte length difference.
     860: 		    // One example is Å (3 bytes) and å (2 bytes).
     861: 		    mch_memmove(ptr + len, s, orig_len);
