     962:     {
     963: 	ga_init2(&dio->dio_diff.dout_ga, sizeof(char *), 1000);
     964:     }
     965:     else
     966:     {
     967: 	// We need three temp file names.
     968: 	dio->dio_orig.din_fname = vim_tempname('o', TRUE);
     969: 	dio->dio_new.din_fname = vim_tempname('n', TRUE);
     970: 	dio->dio_diff.dout_fname = vim_tempname('d', TRUE);
