     981:     // :diffupdate!
     982:     if (eap != NULL && eap->forceit)
     983: 	for (idx_new = idx_orig; idx_new < DB_COUNT; ++idx_new)
     984: 	{
     985: 	    buf = curtab->tp_diffbuf[idx_new];
     986: 	    if (buf_valid(buf))
     987: 		buf_check_timestamp(buf, FALSE);
     988: 	}
     989: 
     990:     // Parse and sort diff anchors if enabled
     991:     int num_anchors = INT_MAX;
     992:     linenr_T anchors[DB_COUNT][MAX_DIFF_ANCHORS];
     993:     CLEAR_FIELD(anchors);
     994:     if (diff_flags & DIFF_ANCHOR)
     995:     {
     996: 	for (int idx = 0; idx < DB_COUNT; idx++)
     997: 	{
     998: 	    if (curtab->tp_diffbuf[idx] == NULL)
     999: 		continue;
    1000: 	    int buf_num_anchors = 0;
    1001: 	    if (parse_diffanchors(FALSE,
    1002: 			curtab->tp_diffbuf[idx],
    1003: 			anchors[idx],
    1004: 			&buf_num_anchors) != OK)
    1005: 	    {
    1006: 		emsg(_(e_failed_to_find_all_diff_anchors));
    1007: 		num_anchors = 0;
    1008: 		CLEAR_FIELD(anchors);
    1009: 		break;
    1010: 	    }
    1011: 	    if (buf_num_anchors < num_anchors)
    1012: 		num_anchors = buf_num_anchors;
    1013: 
    1014: 	    if (buf_num_anchors > 0)
    1015: 		qsort((void *)anchors[idx],
    1016: 			(size_t)buf_num_anchors,
    1017: 			sizeof(linenr_T),
    1018: 			lnum_compare);
    1019: 	}
    1020:     }
    1021:     if (num_anchors == INT_MAX)
    1022: 	num_anchors = 0;
    1023: 
    1024:     // Split the files into multiple sections by anchors. Each section starts
    1025:     // from one anchor (inclusive) and ends at the next anchor (exclusive).
    1026:     // Diff each section separately before combining the results. If we don't
    1027:     // have any anchors, we will have one big section of the entire file.
    1028:     for (int anchor_i = 0; anchor_i <= num_anchors; anchor_i++)
    1029:     {
    1030: 	diff_T	*orig_diff = NULL;
    1031: 	if (anchor_i != 0)
    1032: 	{
    1033: 	    orig_diff = curtab->tp_first_diff;
    1034: 	    curtab->tp_first_diff = NULL;
    1035: 	}
    1036: 	linenr_T lnum_start = (anchor_i == 0) ? 1 : anchors[idx_orig][anchor_i - 1];
    1037: 	linenr_T lnum_end = (anchor_i == num_anchors) ? -1 : anchors[idx_orig][anchor_i] - 1;
    1038: 
    1039: 	// Write the first buffer to a tempfile or mmfile_t.
    1040: 	buf = curtab->tp_diffbuf[idx_orig];
>>  1041: 	if (diff_write(buf, &dio->dio_orig, lnum_start, lnum_end) == FAIL)
    1042: 	{
    1043: 	    if (orig_diff != NULL)
    1044: 	    {
    1045: 		// Clean up in-progress diff blocks
    1046: 		curtab->tp_first_diff = orig_diff;
    1047: 		diff_clear(curtab);
    1048: 	    }
    1049: 	    goto theend;
    1050: 	}
    1051: 
    1052: 	// Make a difference between the first buffer and every other.
>>  1053: 	for (idx_new = idx_orig + 1; idx_new < DB_COUNT; ++idx_new)
    1054: 	{
    1055: 	    buf = curtab->tp_diffbuf[idx_new];
>>  1056: 	    if (buf == NULL || buf->b_ml.ml_mfp == NULL)
    1057: 		continue; // skip buffer that isn't loaded
    1058: 
    1059: 	    lnum_start = anchor_i == 0 ? 1 : anchors[idx_new][anchor_i - 1];
    1060: 	    lnum_end = anchor_i == num_anchors ? -1 : anchors[idx_new][anchor_i] - 1;
    1061: 
    1062: 	    // Write the other buffer and diff with the first one.
>>  1063: 	    if (diff_write(buf, &dio->dio_new, lnum_start, lnum_end) == FAIL)
    1064: 		continue;
>>  1065: 	    if (diff_file(dio) == FAIL)
    1066: 		continue;
    1067: 
    1068: 	    // Read the diff output and add each entry to the diff list.
    1069: 	    diff_read(idx_orig, idx_new, dio);
    1070: 
    1071: 	    clear_diffin(&dio->dio_new);
    1072: 	    clear_diffout(&dio->dio_diff);
    1073: 	}
    1074: 	clear_diffin(&dio->dio_orig);
    1075: 
    1076: 	if (anchor_i != 0)
    1077: 	{
    1078: 	    // Combine the new diff blocks with the existing ones
    1079: 	    for (diff_T *dp = curtab->tp_first_diff; dp != NULL; dp = dp->df_next)
    1080: 	    {
    1081: 		for (int idx = 0; idx < DB_COUNT; idx++)
    1082: 		{
    1083: 		    if (anchors[idx][anchor_i - 1] > 0)
    1084: 			dp->df_lnum[idx] += anchors[idx][anchor_i - 1] - 1;
    1085: 		}
    1086: 	    }
    1087: 	    if (orig_diff != NULL)
    1088: 	    {
    1089: 		diff_T *last_diff = orig_diff;
    1090: 		while (last_diff->df_next != NULL)
    1091: 		    last_diff = last_diff->df_next;
    1092: 		last_diff->df_next = curtab->tp_first_diff;
    1093: 		curtab->tp_first_diff = orig_diff;
    1094: 	    }
    1095: 	}
    1096:     }
    1097: 
    1098: theend:
    1099:     vim_free(dio->dio_orig.din_fname);
    1100:     vim_free(dio->dio_new.din_fname);
    1101:     vim_free(dio->dio_diff.dout_fname);
    1102: }

    2373:     static void
    2374: run_linematch_algorithm(diff_T *dp)
    2375: {
    2376:     // define buffers for diff algorithm
    2377:     diffin_T		diffbufs_mm[DB_COUNT];
    2378:     const mmfile_t	*diffbufs[DB_COUNT];
    2379:     int			diff_length[DB_COUNT];
    2380:     size_t		ndiffs = 0;
    2381: 
    2382:     for (int i = 0; i < DB_COUNT; i++)
    2383:     {
    2384: 	if (curtab->tp_diffbuf[i] != NULL)
    2385: 	{
    2386: 	    // write the contents of the entire buffer to
    2387: 	    // diffbufs_mm[diffbuffers_count]
    2388: 	    if (dp->df_count[i] > 0)
    2389: 	    {
    2390: 		diff_write_buffer(curtab->tp_diffbuf[i], &diffbufs_mm[ndiffs],
    2391: 			dp->df_lnum[i], dp->df_lnum[i] + dp->df_count[i] - 1);
    2392: 	    }
    2393: 	    else
    2394: 	    {
    2395: 		diffbufs_mm[ndiffs].din_mmfile.size = 0;
    2396: 		diffbufs_mm[ndiffs].din_mmfile.ptr = NULL;
    2397: 	    }
    2398: 
    2399: 	    diffbufs[ndiffs] = &diffbufs_mm[ndiffs].din_mmfile;
    2400: 
    2401: 	    // keep track of the length of this diff block to pass it to the
    2402: 	    // linematch algorithm
    2403: 	    diff_length[ndiffs] = dp->df_count[i];
    2404: 
    2405: 	    // increment the amount of diff buffers we are passing to the
    2406: 	    // algorithm
    2407: 	    ndiffs++;
    2408: 	}
    2409:     }
    2410: 
    2411:     // we will get the output of the linematch algorithm in the format of an
    2412:     // array of integers (*decisions) and the length of that array
    2413:     // (decisions_length)
    2414:     int *decisions = NULL;
    2415:     const int iwhite = (diff_flags & (DIFF_IWHITEALL | DIFF_IWHITE)) > 0 ? 1 : 0;
    2416:     size_t decisions_length =
    2417: 	linematch_nbuffers(diffbufs, diff_length, ndiffs, &decisions, iwhite);
    2418: 
>>  2419:     for (size_t i = 0; i < ndiffs; i++)
    2420: 	free(diffbufs_mm[i].din_mmfile.ptr); // TODO should this be vim_free ?
    2421: 
    2422:     apply_linematch_results(dp, decisions_length, decisions);
    2423: 
    2424:     free(decisions);
    2425: }

