    1236:     int
    1237: ex_let_vars(
    1238:     char_u	*arg_start,
    1239:     typval_T	*tv,
    1240:     int		copy,		// copy values from "tv", don't move
    1241:     int		semicolon,	// from skip_var_list()
    1242:     int		var_count,	// from skip_var_list()
    1243:     int		flags,		// ASSIGN_FINAL, ASSIGN_CONST, etc.
    1244:     char_u	*op)
    1245: {
    1246:     char_u	*arg = arg_start;
    1247:     list_T	*l;
    1248:     tuple_T	*tuple = NULL;
    1249:     int		i;
    1250:     int		var_idx = 0;
    1251:     listitem_T	*item = NULL;
    1252:     typval_T	ltv;
    1253:     int		is_list = tv->v_type == VAR_LIST;
    1254:     int		idx;
    1255: 
    1256:     if (tv->v_type == VAR_VOID)
    1257:     {
    1258: 	emsg(_(e_cannot_use_void_value));
    1259: 	return FAIL;
    1260:     }
    1261:     if (*arg != '[')
    1262:     {
    1263: 	// ":let var = expr" or ":for var in list"
    1264: 	if (ex_let_one(arg, tv, copy, flags, op, op, var_idx) == NULL)
    1265: 	    return FAIL;
    1266: 	return OK;
    1267:     }
    1268: 
    1269:     // ":let [v1, v2] = list" or ":for [v1, v2] in listlist"
    1270:     // or
    1271:     // ":let [v1, v2] = tuple" or ":for [v1, v2] in tupletuple"
    1272:     if (tv->v_type != VAR_LIST && tv->v_type != VAR_TUPLE)
    1273:     {
    1274: 	emsg(_(e_list_or_tuple_required));
    1275: 	return FAIL;
    1276:     }
    1277:     if (is_list)
    1278:     {
    1279: 	l = tv->vval.v_list;
    1280: 	if (l == NULL)
    1281: 	{
    1282: 	    emsg(_(e_list_required));
    1283: 	    return FAIL;
    1284: 	}
    1285: 	i = list_len(l);
    1286:     }
    1287:     else
    1288:     {
    1289: 	tuple = tv->vval.v_tuple;
    1290: 	if (tuple == NULL)
    1291: 	{
    1292: 	    emsg(_(e_tuple_required));
    1293: 	    return FAIL;
    1294: 	}
    1295: 	i = tuple_len(tuple);
    1296:     }
    1297: 
    1298:     if (semicolon == 0 && var_count < i)
    1299:     {
    1300: 	emsg(_(is_list ? e_less_targets_than_list_items
    1301: 					: e_less_targets_than_tuple_items));
    1302: 	return FAIL;
    1303:     }
    1304:     if (var_count - semicolon > i)
    1305:     {
    1306: 	emsg(_(is_list ? e_more_targets_than_list_items
    1307: 					: e_more_targets_than_tuple_items));
    1308: 	return FAIL;
    1309:     }
    1310: 
    1311:     if (is_list)
    1312:     {
    1313: 	CHECK_LIST_MATERIALIZE(l);
    1314: 	item = l->lv_first;
    1315:     }
    1316:     else
    1317: 	idx = 0;
    1318: 
    1319:     while (*arg != ']')
    1320:     {
    1321: 	arg = skipwhite(arg + 1);
    1322: 	++var_idx;
    1323: 	arg = ex_let_one(arg, is_list ? &item->li_tv : TUPLE_ITEM(tuple, idx),
    1324: 			 TRUE, flags | ASSIGN_UNPACK, (char_u *)",;]", op,
    1325: 			 var_idx);
    1326: 	if (is_list)
    1327: 	    item = item->li_next;
    1328: 	else
    1329: 	    idx++;
    1330: 	if (arg == NULL)
    1331: 	    return FAIL;
    1332: 
    1333: 	arg = skipwhite(arg);
    1334: 	if (*arg == ';')
    1335: 	{
    1336: 	    // Put the rest of the list or tuple (may be empty) in the var
    1337: 	    // after ';'.  Create a new list or tuple for this.
    1338: 	    if (is_list)
    1339: 	    {
    1340: 		// Put the rest of the list (may be empty) in the var
    1341: 		// after ';'.  Create a new list for this.
    1342: 		l = list_alloc();
    1343: 		if (l == NULL)
    1344: 		    return FAIL;
    1345: 
    1346: 		// list
    1347: 		while (item != NULL)
    1348: 		{
    1349: 		    list_append_tv(l, &item->li_tv);
    1350: 		    item = item->li_next;
    1351: 		}
    1352: 
    1353: 		ltv.v_type = VAR_LIST;
    1354: 		ltv.v_lock = 0;
    1355: 		ltv.vval.v_list = l;
    1356: 		l->lv_refcount = 1;
    1357: 	    }
    1358: 	    else
    1359: 	    {
>>  1360: 		tuple_T	*new_tuple = tuple_alloc();
    1361: 		if (new_tuple == NULL)
    1362: 		    return FAIL;
    1363: 
    1364: 		// Put the rest of the tuple (may be empty) in the var
    1365: 		// after ';'.  Create a new tuple for this.
    1366: 		while (idx < TUPLE_LEN(tuple))
    1367: 		{
    1368: 		    typval_T    new_tv;
    1369: 
    1370: 		    copy_tv(TUPLE_ITEM(tuple, idx), &new_tv);
    1371: 		    if (tuple_append_tv(new_tuple, &new_tv) == FAIL)
    1372: 			return FAIL;
    1373: 		    idx++;
    1374: 		}
    1375: 
    1376: 		ltv.v_type = VAR_TUPLE;
    1377: 		ltv.v_lock = 0;
    1378: 		ltv.vval.v_tuple = new_tuple;
    1379: 		new_tuple->tv_refcount = 1;
    1380: 	    }
    1381: 
    1382: 	    ++var_idx;
    1383: 	    arg = ex_let_one(skipwhite(arg + 1), &ltv, FALSE,
    1384: 			flags | ASSIGN_UNPACK, (char_u *)"]", op, var_idx);
    1385: 	    clear_tv(&ltv);
    1386: 	    if (arg == NULL)
    1387: 		return FAIL;
    1388: 	    break;
    1389: 	}
    1390: 	else if (*arg != ',' && *arg != ']')
    1391: 	{
    1392: 	    internal_error("ex_let_vars()");
    1393: 	    return FAIL;
    1394: 	}
    1395:     }
    1396: 
    1397:     return OK;
    1398: }

