    1050: 		// than LSIZE:
    1051: 		//     |{bartype},>{length of "{text}{text2}"}
    1052: 		//     |<"{text1}
    1053: 		//     |<{text2}",{value}
    1054: 		// Length includes the quotes.
    1055: 		++p;
