>>  1057: 		buf = alloc(len + 1);
    1058: 		if (buf == NULL)
    1059: 		    return TRUE;
    1060: 		p = buf;
>>  1061: 		for (todo = len; todo > 0; todo -= n)
    1062: 		{
    1063: 		    eof = viminfo_readline(virp);
>>  1064: 		    if (eof || virp->vir_line[0] != '|'
>>  1065: 						  || virp->vir_line[1] != '<')
    1066: 		    {
    1067: 			// File was truncated or garbled. Read another line if
    1068: 			// this one starts with '|'.
    1069: 			vim_free(buf);
    1070: 			return eof || virp->vir_line[0] == '|';
    1071: 		    }
